def predict(triples: list[Triple]) -> str:
    """Generate a readable sentence from a list of triples."""
    if not triples:
        return ""

    # Group triples by subject to enable better sentence construction
    from collections import defaultdict
    subject_triples: dict[str, list[Triple]] = defaultdict(list)
    for t in triples:
        subject_triples[t.subject].append(t)

    # Track subjects already mentioned to avoid repetition
    mentioned_subjects: set[str] = set()
    parts: list[str] = []

    # Process triples with priority for airport-related subjects
    sorted_subjects = sorted(subject_triples.keys(), key=lambda s: len(s))

    for subject in sorted_subjects:
        subject_triple_list = subject_triples[subject]

        # Check if this subject is already mentioned in a previous part
        if subject in mentioned_subjects:
            # Create relative clause instead of repeating subject
            relative_clauses = []
            for t in subject_triple_list:
                p, o = t.predicate, t.object
                clause = _predicate_to_clause(p, o, use_relative=True)
                if clause:
                    relative_clauses.append(clause)

            if relative_clauses:
                # Join with "which" for relative clause
                if len(relative_clauses) == 1:
                    parts.append(f"which {relative_clauses[0]}")
                else:
                    combined = ", ".join(relative_clauses[:-1]) + ", and " + relative_clauses[-1]
                    parts.append(f"which {combined}")
            continue

        # Build main clause for this subject
        clauses = []
        for t in subject_triple_list:
            p, o = t.predicate, t.object
            clause = _predicate_to_clause(p, o, use_relative=False)
            if clause:
                clauses.append(clause)

        if clauses:
            # First clause uses subject, others use relative pronoun
            main_clause = clauses[0]
            if len(clauses) == 1:
                parts.append(main_clause)
            else:
                # Combine with relative clause
                remaining = clauses[1:]
                if len(remaining) == 1:
                    combined = f"{main_clause}, which {remaining[0]}"
                else:
                    combined_clauses = ", ".join(remaining[:-1]) + ", and " + remaining[-1]
                    combined = f"{main_clause}, which {combined_clauses}"
                parts.append(combined)

            mentioned_subjects.add(subject)

    # Join all parts into a single fluent complex sentence
    if len(parts) == 1:
        sentence = parts[0] + "."
    elif len(parts) == 2:
        sentence = parts[0] + ", and " + parts[1] + "."
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
    # Ensure the first character is capitalised
    return sentence[0].upper() + sentence[1:]

